namespace NapsternetVClient.Utilities;

public static class Base64Helper
{
    public static string DecodeBase64(string input)
    {
        if (!TryDecodeBase64(input, out string? decoded) || decoded is null)
            throw new FormatException("Invalid Base64 content");
        return decoded;
    }

    public static bool TryDecodeBase64(string input, out string? decoded)
    {
        decoded = null;
        if (string.IsNullOrWhiteSpace(input))
            return false;

        string normalized = input.Trim()
            .Replace('-', '+')
            .Replace('_', '/');

        int mod = normalized.Length % 4;
        if (mod > 0)
            normalized += new string('=', 4 - mod);

        try
        {
            byte[] bytes = Convert.FromBase64String(normalized);
            decoded = Encoding.UTF8.GetString(bytes);
            return true;
        }
        catch
        {
            return false;
        }
    }
}

