namespace NapsternetVClient.Utilities;

public static class CryptoHelper
{
    public static string DecryptNpvData(string encryptedBase64, string password)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(password, nameof(password));
        ArgumentException.ThrowIfNullOrWhiteSpace(encryptedBase64, nameof(encryptedBase64));

        byte[] encryptedBytes = Convert.FromBase64String(encryptedBase64);
        byte[] key = SHA256.HashData(Encoding.UTF8.GetBytes(password));
        byte[] ivFull = MD5.HashData(Encoding.UTF8.GetBytes(password));
        byte[] iv = ivFull[..16];

        using var aes = Aes.Create();
        aes.Key = key;
        aes.IV = iv;
        aes.Mode = CipherMode.CBC;
        aes.Padding = PaddingMode.PKCS7;

        using var decryptor = aes.CreateDecryptor();
        byte[] decryptedBytes = decryptor.TransformFinalBlock(encryptedBytes, 0, encryptedBytes.Length);
        return Encoding.UTF8.GetString(decryptedBytes);
    }

    public static string? TryDecryptNpvData(string encryptedBase64, string password)
    {
        try
        {
            return DecryptNpvData(encryptedBase64, password);
        }
        catch (CryptographicException) { }

        try
        {
            byte[] encryptedBytes = Convert.FromBase64String(encryptedBase64);
            byte[] md5Key = MD5.HashData(Encoding.UTF8.GetBytes(password));
            byte[] key = new byte[32];
            Array.Copy(md5Key, key, 16);
            byte[] sha256 = SHA256.HashData(Encoding.UTF8.GetBytes(password));
            byte[] iv = sha256[..16];

            using var aes = Aes.Create();
            aes.Key = key;
            aes.IV = iv;
            aes.Mode = CipherMode.CBC;
            aes.Padding = PaddingMode.PKCS7;

            using var decryptor = aes.CreateDecryptor();
            byte[] decryptedBytes = decryptor.TransformFinalBlock(encryptedBytes, 0, encryptedBytes.Length);
            return Encoding.UTF8.GetString(decryptedBytes);
        }
        catch (CryptographicException) { }

        try
        {
            byte[] encryptedBytes = Convert.FromBase64String(encryptedBase64);
            byte[] salt = Encoding.UTF8.GetBytes("NapsternetV");
            using var pbkdf2 = new Rfc2898DeriveBytes(password, salt, 10000, HashAlgorithmName.SHA1);
            byte[] key = pbkdf2.GetBytes(32);
            byte[] iv = pbkdf2.GetBytes(16);

            using var aes = Aes.Create();
            aes.Key = key;
            aes.IV = iv;
            aes.Mode = CipherMode.CBC;
            aes.Padding = PaddingMode.PKCS7;

            using var decryptor = aes.CreateDecryptor();
            byte[] decryptedBytes = decryptor.TransformFinalBlock(encryptedBytes, 0, encryptedBytes.Length);
            string result = Encoding.UTF8.GetString(decryptedBytes);
            if (result.TrimStart().StartsWith('{'))
                return result;
        }
        catch { }

        return null;
    }
}

