namespace NapsternetVClient.Parsers;

public sealed class NpvtParser : IConfigParser
{
    private readonly NpvtDecoder _decoder;
    private readonly ILogger<NpvtParser> _logger;

    public NpvtParser(NpvtDecoder decoder, ILogger<NpvtParser> logger)
    {
        _decoder = decoder;
        _logger = logger;
    }

    public bool CanParse(string content, string? fileExtension = null) =>
        FormatSniffer.Detect(content, fileExtension) == ConfigFormat.Npvt;

    public async Task<IReadOnlyList<ServerProfile>> ParseAsync(string content, string? password = null, string? sourceFile = null)
    {
        string sourceName = string.IsNullOrEmpty(sourceFile) ? "NPVT Config" : Path.GetFileNameWithoutExtension(sourceFile);
        string json;

        if (!string.IsNullOrEmpty(sourceFile) && File.Exists(sourceFile))
            json = await _decoder.DecodeFileAsync(sourceFile, password);
        else
            json = await _decoder.DecodeContentAsync(content, password);

        _logger.LogInformation("NPVT decoded successfully for {Source}", sourceName);

        NpvWrapper? wrapper = JsonHelper.Deserialize<NpvWrapper>(json);
        if (wrapper?.Config is not null)
            return [NpvtProfileMapper.MapFromWrapper(wrapper, sourceName)];

        NpvConfig? directConfig = JsonHelper.Deserialize<NpvConfig>(json);
        if (directConfig is not null && !string.IsNullOrEmpty(directConfig.Address))
        {
            return [NpvtProfileMapper.MapConfig(directConfig, "vmess", sourceName)];
        }

        throw new FormatException("Decoded NPVT content is not a recognized config structure.");
    }
}

using System.Text.Json;
using Microsoft.Extensions.Logging;
using NapsternetVClient.Models;
using NapsternetVClient.Utilities;

namespace NapsternetVClient.Parsers;

public sealed class NpvParser : IConfigParser
{
    private readonly ILogger<NpvParser> _logger;

    public NpvParser(ILogger<NpvParser> logger)
    {
        _logger = logger;
    }

    public bool CanParse(string content, string? fileExtension = null)
    {
        var format = FormatSniffer.Detect(content, fileExtension);
        return format is ConfigFormat.Npv4 or ConfigFormat.PlainJson;
    }

    public Task<IReadOnlyList<ServerProfile>> ParseAsync(string content, string? password = null, string? sourceFile = null)
    {
        return Task.Run(() => ParseInternal(content, password, sourceFile));
    }

    private IReadOnlyList<ServerProfile> ParseInternal(string content, string? password, string? sourceFile)
    {
        string trimmed = content.Trim();
        string json = trimmed.TrimStart().StartsWith('{')
            ? trimmed
            : Base64Helper.DecodeBase64(trimmed);

        NpvWrapper? wrapper = JsonHelper.Deserialize<NpvWrapper>(json)
            ?? throw new FormatException("Invalid NPV wrapper JSON");

        _logger.LogInformation("NPV version {Version}, type {Type}, locked {Locked}",
            wrapper.Version, wrapper.Type, wrapper.Locked);

        NpvWrapper configWrapper;
        if (wrapper.Locked)
        {
            if (string.IsNullOrEmpty(password))
                throw new InvalidOperationException("This config file is password-protected. Please provide a password.");
            if (string.IsNullOrEmpty(wrapper.Data))
                throw new FormatException("Locked NPV file has no encrypted data field");

            string? decryptedJson = CryptoHelper.TryDecryptNpvData(wrapper.Data, password)
                ?? throw new InvalidOperationException("Failed to decrypt the config file. The password may be incorrect.");

            if (decryptedJson.Contains("\"config\"", StringComparison.Ordinal))
            {
                configWrapper = JsonHelper.Deserialize<NpvWrapper>(decryptedJson)
                    ?? throw new FormatException("Failed to parse decrypted NPV wrapper");
            }
            else
            {
                configWrapper = new NpvWrapper
                {
                    Version = wrapper.Version,
                    Type = wrapper.Type,
                    Locked = false,
                    Config = JsonHelper.Deserialize<NpvConfig>(decryptedJson)
                };
            }
        }
        else
        {
            configWrapper = wrapper;
        }

        if (configWrapper.Config is null)
            throw new FormatException("NPV config section is missing");

        string sourceName = string.IsNullOrEmpty(sourceFile)
            ? "NPV Config"
            : Path.GetFileNameWithoutExtension(sourceFile);

        return [NpvtProfileMapper.MapFromWrapper(configWrapper, sourceName)];
    }
}

