using Microsoft.Extensions.Logging;
using NapsternetVClient.Models;
using NapsternetVClient.Utilities;

namespace NapsternetVClient.Parsers;

public sealed class ShareLinkParser : IConfigParser
{
    private readonly ILogger<ShareLinkParser> _logger;

    public ShareLinkParser(ILogger<ShareLinkParser> logger)
    {
        _logger = logger;
    }

    public bool CanParse(string content, string? fileExtension = null) =>
        FormatSniffer.Detect(content, fileExtension) == ConfigFormat.ShareUri;

    public Task<IReadOnlyList<ServerProfile>> ParseAsync(string content, string? password = null, string? sourceFile = null)
    {
        var results = new List<ServerProfile>();
        var lines = content.Split(['\r', '\n'], StringSplitOptions.RemoveEmptyEntries);

        foreach (string line in lines)
        {
            string trimmed = line.Trim();
            try
            {
                ServerProfile? profile = trimmed switch
                {
                    _ when trimmed.StartsWith("vmess://", StringComparison.OrdinalIgnoreCase) => ParseVmess(trimmed),
                    _ when trimmed.StartsWith("vless://", StringComparison.OrdinalIgnoreCase) => ParseVless(trimmed),
                    _ when trimmed.StartsWith("trojan://", StringComparison.OrdinalIgnoreCase) => ParseTrojan(trimmed),
                    _ when trimmed.StartsWith("ss://", StringComparison.OrdinalIgnoreCase) => ParseShadowsocks(trimmed),
                    _ => null
                };

                if (profile is not null)
                    results.Add(profile);
            }
            catch (Exception ex)
            {
                _logger.LogWarning(ex, "Failed to parse URI");
            }
        }

        return Task.FromResult<IReadOnlyList<ServerProfile>>(results);
    }

    private static ServerProfile ParseVmess(string uri)
    {
        string base64 = uri["vmess://".Length..];
        string json = Base64Helper.DecodeBase64(base64);
        using var doc = JsonDocument.Parse(json);
        var root = doc.RootElement;

        return new ServerProfile
        {
            Protocol = ProxyProtocol.Vmess,
            Name = root.GetPropertyOrDefault("ps", "VMess Server"),
            Address = root.GetPropertyOrDefault("add", ""),
            Port = int.Parse(root.GetPropertyOrDefault("port", "443")),
            UserId = root.GetPropertyOrDefault("id", ""),
            AlterId = int.Parse(root.GetPropertyOrDefault("aid", "0")),
            Security = root.GetPropertyOrDefault("scy", "auto"),
            Network = ParseTransport(root.GetPropertyOrDefault("net", "tcp")),
            TlsSecurity = root.GetPropertyOrDefault("tls", ""),
            Sni = root.GetPropertyOrDefault("sni", ""),
            WsPath = root.GetPropertyOrDefault("path", ""),
            WsHost = root.GetPropertyOrDefault("host", ""),
            TcpHeaderType = root.GetPropertyOrDefault("type", "none"),
            Alpn = root.GetPropertyOrDefault("alpn", ""),
            Fingerprint = root.GetPropertyOrDefault("fp", "")
        };
    }

    private static ServerProfile ParseVless(string uri)
    {
        var parsed = new Uri(uri);
        NameValueCollection query = QueryStringHelper.Parse(parsed.Query);

        return new ServerProfile
        {
            Protocol = ProxyProtocol.Vless,
            Name = Uri.UnescapeDataString(parsed.Fragment.TrimStart('#')),
            Address = parsed.Host,
            Port = parsed.Port > 0 ? parsed.Port : 443,
            UserId = parsed.UserInfo,
            Security = query["encryption"] ?? "none",
            Flow = query["flow"] ?? string.Empty,
            Network = ParseTransport(query["type"] ?? "tcp"),
            TlsSecurity = query["security"] ?? string.Empty,
            Sni = query["sni"] ?? string.Empty,
            Alpn = query["alpn"] ?? string.Empty,
            Fingerprint = query["fp"] ?? string.Empty,
            WsPath = query["path"] ?? string.Empty,
            WsHost = query["host"] ?? string.Empty,
            GrpcServiceName = query["serviceName"] ?? string.Empty,
            GrpcMode = query["mode"] ?? "gun",
            RealityPublicKey = query["pbk"] ?? string.Empty,
            RealityShortId = query["sid"] ?? string.Empty,
            RealitySpiderX = query["spx"] ?? string.Empty
        };
    }

    private static ServerProfile ParseTrojan(string uri)
    {
        var parsed = new Uri(uri);
        NameValueCollection query = QueryStringHelper.Parse(parsed.Query);

        return new ServerProfile
        {
            Protocol = ProxyProtocol.Trojan,
            Name = Uri.UnescapeDataString(parsed.Fragment.TrimStart('#')),
            Address = parsed.Host,
            Port = parsed.Port > 0 ? parsed.Port : 443,
            Password = Uri.UnescapeDataString(parsed.UserInfo),
            Network = ParseTransport(query["type"] ?? "tcp"),
            TlsSecurity = query["security"] ?? "tls",
            Sni = query["sni"] ?? parsed.Host,
            Alpn = query["alpn"] ?? string.Empty,
            Fingerprint = query["fp"] ?? string.Empty,
            WsPath = query["path"] ?? string.Empty,
            WsHost = query["host"] ?? string.Empty
        };
    }

    private static ServerProfile ParseShadowsocks(string uri)
    {
        string withoutScheme = uri["ss://".Length..];
        string name = string.Empty;
        int hashIdx = withoutScheme.LastIndexOf('#');
        if (hashIdx >= 0)
        {
            name = Uri.UnescapeDataString(withoutScheme[(hashIdx + 1)..]);
            withoutScheme = withoutScheme[..hashIdx];
        }

        string address;
        int port;
        string method;
        string password;

        int atIdx = withoutScheme.LastIndexOf('@');
        if (atIdx >= 0)
        {
            string userInfo = Base64Helper.DecodeBase64(withoutScheme[..atIdx]);
            string hostPort = withoutScheme[(atIdx + 1)..];
            var parts = userInfo.Split(':', 2);
            method = parts[0];
            password = parts.Length > 1 ? parts[1] : string.Empty;
            var hp = hostPort.Split(':');
            address = hp[0];
            port = int.Parse(hp[1]);
        }
        else
        {
            string decoded = Base64Helper.DecodeBase64(withoutScheme);
            var methodRest = decoded.Split(':', 2);
            method = methodRest[0];
            var passHostPort = methodRest[1].Split('@');
            password = passHostPort[0];
            var hp = passHostPort[1].Split(':');
            address = hp[0];
            port = int.Parse(hp[1]);
        }

        return new ServerProfile
        {
            Protocol = ProxyProtocol.Shadowsocks,
            Name = string.IsNullOrEmpty(name) ? $"SS {address}:{port}" : name,
            Address = address,
            Port = port,
            Security = method,
            Password = password
        };
    }

    private static TransportType ParseTransport(string network) => network.ToLowerInvariant() switch
    {
        "ws" or "websocket" => TransportType.Ws,
        "grpc" or "gun" => TransportType.Grpc,
        "h2" or "http" => TransportType.H2,
        "quic" => TransportType.Quic,
        "kcp" or "mkcp" => TransportType.Kcp,
        _ => TransportType.Tcp
    };
}

internal static class JsonElementExtensions
{
    public static string GetPropertyOrDefault(this JsonElement element, string propertyName, string defaultValue)
    {
        if (element.TryGetProperty(propertyName, out var prop))
        {
            return prop.ValueKind switch
            {
                JsonValueKind.String => prop.GetString() ?? defaultValue,
                JsonValueKind.Number => prop.GetRawText(),
                _ => defaultValue
            };
        }
        return defaultValue;
    }
}

internal static class QueryStringHelper
{
    public static NameValueCollection Parse(string query)
    {
        var result = new NameValueCollection();
        if (string.IsNullOrEmpty(query))
            return result;

        string q = query.TrimStart('?');
        foreach (string pair in q.Split('&', StringSplitOptions.RemoveEmptyEntries))
        {
            var parts = pair.Split('=', 2);
            string key = Uri.UnescapeDataString(parts[0]);
            string value = parts.Length > 1 ? Uri.UnescapeDataString(parts[1]) : string.Empty;
            result[key] = value;
        }
        return result;
    }
}

using Microsoft.Extensions.Logging;
using NapsternetVClient.Models;

namespace NapsternetVClient.Parsers;

public sealed class ParserFactory
{
    private readonly IReadOnlyList<IConfigParser> _parsers;
    private readonly ILogger<ParserFactory> _logger;

    public ParserFactory(ILoggerFactory loggerFactory)
    {
        _logger = loggerFactory.CreateLogger<ParserFactory>();
        var npvtDecoder = new NpvtDecoder(loggerFactory.CreateLogger<NpvtDecoder>());
        _parsers =
        [
            new NpvtParser(npvtDecoder, loggerFactory.CreateLogger<NpvtParser>()),
            new NpvParser(loggerFactory.CreateLogger<NpvParser>()),
            new ShareLinkParser(loggerFactory.CreateLogger<ShareLinkParser>())
        ];
    }

    public async Task<IReadOnlyList<ServerProfile>> ParseAsync(
        string content,
        string? fileExtension = null,
        string? password = null,
        string? sourceFile = null)
    {
        var format = FormatSniffer.Detect(content, fileExtension);
        _logger.LogInformation("Detected config format: {Format}", format);

        foreach (var parser in _parsers)
        {
            if (parser.CanParse(content, fileExtension))
            {
                _logger.LogInformation("Using parser: {Parser}", parser.GetType().Name);
                return await parser.ParseAsync(content, password, sourceFile);
            }
        }

        throw new FormatException(
            $"No parser found for content (extension: {fileExtension ?? "none"}). " +
            "Supported: .npvt, .npv4, vmess://, vless://, trojan://, ss://");
    }

    public async Task<IReadOnlyList<ServerProfile>> ImportFileAsync(string filePath, string? password = null)
    {
        string content = await File.ReadAllTextAsync(filePath);
        string extension = Path.GetExtension(filePath).ToLowerInvariant();
        var profiles = await ParseAsync(content, extension, password, filePath);

        foreach (var profile in profiles)
            profile.SourceFile = Path.GetFileName(filePath);

        return profiles;
    }
}

